function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use a priority queue to perform Dijkstra-like search
    // We'll keep track of the maximum minimum edge cost for each node
    const maxMinCost = new Array(n).fill(0);
    const pq = new MaxPriorityQueue<{ node: number, minEdge: number, totalCost: number }>();

    // Start from node 0
    pq.enqueue({ node: 0, minEdge: Infinity, totalCost: 0 });
    maxMinCost[0] = Infinity;

    while (!pq.isEmpty()) {
        const { node, minEdge, totalCost } = pq.dequeue();

        // If we've reached the destination node, return the max min edge
        if (node === n - 1) {
            return minEdge;
        }

        // Skip if we've already found a better path to this node
        if (maxMinCost[node] > minEdge) {
            continue;
        }

        // Traverse all neighbors
        if (graph.has(node)) {
            for (const [neighbor, cost] of graph.get(node)!.entries()) {
                // Skip if the neighbor is offline
                if (!online[neighbor]) {
                    continue;
                }

                // Check if the neighbor is the destination
                if (neighbor === n - 1) {
                    // If the total cost is within k, update the max min edge
                    if (totalCost + cost <= k) {
                        const newMinEdge = Math.min(minEdge, cost);
                        if (newMinEdge > maxMinCost[neighbor]) {
                            maxMinCost[neighbor] = newMinEdge;
                            pq.enqueue({ node: neighbor, minEdge: newMinEdge, totalCost: totalCost + cost });
                        }
                    }
                    continue;
                }

                // Check if the path is valid
                if (totalCost + cost <= k) {
                    const newMinEdge = Math.min(minEdge, cost);
                    if (newMinEdge > maxMinCost[neighbor]) {
                        maxMinCost[neighbor] = newMinEdge;
                        pq.enqueue({ node: neighbor, minEdge: newMinEdge, totalCost: totalCost + cost });
                    }
                }
            }
        }
    }

    // If no valid path is found
    return -1;
}

