import com.google.common.collect.MaxPriorityQueue

fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val graph = HashMap<Long, HashMap<Long, Long>>()

    // Build the graph
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val cost = edge[2]
        graph.putIfAbsent(u, HashMap())
        graph[u]!!.put(v, cost)
    }

    // Use a priority queue to perform Dijkstra-like search
    // We'll keep track of the maximum minimum edge cost for each node
    val maxMinCost = arrayOf<Long>(0L.toDouble()).toTypedArray().apply {
        for (i in 0 until n) {
            this[i] = 0L
        }
    }
    val pq = MaxPriorityQueue({ a, b -> a.minEdge.compareTo(b.minEdge) }) {
        it@node -> {
            it.node = node.node
            it.minEdge = node.minEdge
            it.totalCost = node.totalCost
        }
    }

    // Start from node 0
    pq.enqueue(Node(0, Long.MAX_VALUE, 0L))
    maxMinCost[0] = Long.MAX_VALUE

    while (pq.isNotEmpty()) {
        val node = pq.dequeue()
        val currentNode = node.node
        val currentMinEdge = node.minEdge
        val currentTotalCost = node.totalCost

        // If we've reached the destination node, return the max min edge
        if (currentNode == n - 1L) {
            return currentMinEdge
        }

        // Skip if we've already found a better path to this node
        if (maxMinCost[currentNode] > currentMinEdge) {
            continue
        }

        // Traverse all neighbors
        if (graph.containsKey(currentNode)) {
            for (entry in graph[currentNode]!!.entries) {
                val neighbor = entry.key
                val cost = entry.value

                // Skip if the neighbor is offline
                if (!online[neighbor.toInt()]) {
                    continue
                }

                // Check if the neighbor is the destination
                if (neighbor == n - 1L) {
                    // If the total cost is within k, update the max min edge
                    if (currentTotalCost + cost <= k) {
                        val newMinEdge = Math.min(currentMinEdge, cost)
                        if (newMinEdge > maxMinCost[neighbor.toInt()]) {
